const { createHash, randomUUID } = require('crypto');

const UUID_PATTERN = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

function uuidFromString(input) {
  const hash = createHash('sha1').update(String(input)).digest();
  hash[6] = (hash[6] & 0x0f) | 0x50;
  hash[8] = (hash[8] & 0x3f) | 0x80;
  const hex = hash.toString('hex');
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
}

function ensureUuid(candidate, fallbackSeed) {
  if (typeof candidate === 'string') {
    const normalized = candidate.trim();
    if (UUID_PATTERN.test(normalized)) {
      return normalized.toLowerCase();
    }
    if (normalized.length > 0) {
      return uuidFromString(normalized);
    }
  }
  const seed = fallbackSeed ?? randomUUID();
  return uuidFromString(seed);
}

function safeNodeData(name) {
  try {
    const handle = $(name);
    if (!handle) {
      return null;
    }
    if (typeof handle.first === 'function') {
      const firstItem = handle.first();
      return firstItem?.json ?? null;
    }
    return handle.item?.json ?? null;
  } catch (error) {
    return null;
  }
}

function firstNonEmpty(...values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim().length > 0) {
      return value.trim();
    }
  }
  return '';
}

const telegramMessage = safeNodeData('Telegram Message Trigger')?.message ?? null;
const input = $json ?? {};

let text = firstNonEmpty(input.text, input.messageText, input.message);
let platform = input.platform ?? (telegramMessage ? 'telegram' : null);
let messageType = input.messageType ?? (telegramMessage?.voice ? 'voice' : 'text');

let chatId = input.chatId ?? telegramMessage?.chat?.id ?? null;
if (chatId != null) {
  chatId = String(chatId);
}

let messageId = input.telegramMessageId ?? telegramMessage?.message_id ?? null;
if (messageId != null) {
  messageId = String(messageId);
}

let userId = input.userId ?? null;
if (!userId) {
  if (platform === 'telegram' && telegramMessage?.from?.id != null) {
    userId = `telegram:${telegramMessage.from.id}`;
  } else if (chatId) {
    userId = `${platform ?? 'unknown'}:${chatId}`;
  } else if (messageId) {
    userId = `${platform ?? 'unknown'}:${messageId}`;
  }
}

if (!text) {
  text = firstNonEmpty(telegramMessage?.text, telegramMessage?.caption, input.rawText);
}

const attachments = [];
if (telegramMessage?.voice) {
  attachments.push({
    type: 'telegram_voice',
    fileId: telegramMessage.voice.file_id,
    duration: telegramMessage.voice.duration ?? null,
  });
  if (messageType === 'text') {
    messageType = 'voice';
  }
}

if (!platform) {
  platform = 'unknown';
}

const timestamp = new Date().toISOString();

let sessionId = input.sessionId ?? null;
if (!sessionId && chatId) {
  sessionId = `${platform}:${chatId}`;
} else if (!sessionId && messageId) {
  sessionId = `${platform}:${messageId}`;
}

sessionId = ensureUuid(sessionId, `${platform}:${chatId ?? messageId ?? timestamp}`);

const messageText = text.trim();
const contentForStore = messageText.length > 0 ? messageText : '(empty message)';
const memoryQuery = messageText.length > 0 ? messageText : messageType === 'voice' ? 'recent voice message transcription' : 'recent chat context';

const metadata = {
  platform,
  messageType,
  chatId,
  messageId,
  workflow: 'chat',
  timestamp,
};

if (attachments.length > 0) {
  metadata.attachments = attachments;
}

const conversationStorePayload = {
  sessionId,
  role: 'user',
  content: contentForStore,
  userId,
  metadata,
};

if (messageText.length > 0) {
  conversationStorePayload.embeddingText = messageText;
}

return {
  json: {
    platform,
    messageType,
    messageText,
    memoryQuery,
    chatId,
    messageId,
    userId,
    sessionId,
    timestamp,
    attachments,
    telegram: telegramMessage,
    rawInput: input,
    conversationStorePayload,
  },
};

// Build minimal agent context and instruct the AI to load its own persona and project data via MCP tools
const base = $('Normalize Chat Event').item?.json ?? {};
const storeResponse = $('Store User Turn').item?.json ?? {};

const storedTurn = storeResponse.data?.turn ?? null;
const recentSummary = storedTurn
  ? [`USER (${storedTurn.timestamp ?? 'recent'}): ${String(storedTurn.content ?? '')}`]
  : ['No stored turns available.'];

const systemPrompt = [
  'You are Casey, an AI collaborator for Mylo. Keep responses succinct, warm, and actionable.',
  '## Non-negotiable startup steps',
  'Before you do anything else, you MUST execute these tools in order:',
  '1. Run MCP tool `prompt_get` with payload {"persona_name":"chat"}. Treat the returned prompt content as your authoritative persona/system guidance for this conversation.',
  '2. Run MCP tool `prompt_list` with payload {"type":"project"}. Capture every project prompt (slug and title at minimum) so you can speak about any initiative on demand.',
  'Do not continue until both calls succeed. If either call fails, attempt a reasonable retry or surface the failure to the user before continuing.',
  'Only after the startup steps are complete may you analyse the latest user input provided below. Use additional MCP tools or workflows as needed, and cite whichever tools or datasets inform your reply.',
  '## Latest user input',
  ...recentSummary,
].join('

');

return {
  json: {
    persona: null,
    project: null,
    session: {
      id: base.sessionId,
      originalId: base.sessionId,
      userId: base.userId ?? null,
    },
    message: {
      text: base.messageText ?? '',
      type: base.messageType ?? 'text',
      timestamp: base.timestamp ?? new Date().toISOString(),
      telegramChatId: base.chatId ?? null,
      telegramMessageId: base.messageId ?? null,
      platform: base.platform ?? 'unknown',
    },
    platform: base.platform ?? 'unknown',
    attachments: base.attachments ?? [],
    memory: {
      recentTurns: storedTurn ? [storedTurn] : [],
    },
    conversation: {
      userTurn: storedTurn,
    },
    systemPrompt,
    telemetry: {
      userStore: storeResponse,
    },
  },
};

const context = $('Assemble Agent Context').item?.json ?? {};
const rawOutput = $json.output ?? $json.result ?? $json.response ?? $json;
let content = typeof rawOutput === 'string' ? rawOutput : rawOutput?.output ?? null;
if (!content || typeof content !== 'string' || content.trim().length === 0) {
  content = JSON.stringify(rawOutput, null, 2);
}
const trimmed = content.length > 12000 ? `${content.slice(0, 11997)}...` : content;
const timestamp = new Date().toISOString();

const metadata = {
  platform: context.platform,
  personaId: context.persona?.id ?? null,
  projectId: context.project?.id ?? null,
  workflow: 'chat',
  timestamp,
};

if (context.message?.telegramChatId) {
  metadata.chatId = context.message.telegramChatId;
}
if (context.message?.telegramMessageId) {
  metadata.messageId = context.message.telegramMessageId;
}

const payload = {
  sessionId: context.session?.id,
  role: 'assistant',
  content: trimmed,
  userId: context.session?.userId ?? null,
  metadata,
  embeddingText: trimmed,
};

return {
  json: {
    ...context,
    agentOutput: trimmed,
    responseText: trimmed,
    conversationStorePayload: payload,
  },
};

const context = $('Prepare Assistant Store Request').item?.json ?? {};
const assistantStore = $json.data?.turn ?? null;

return {
  json: {
    responseText: context.responseText,
    persona: context.persona ?? null,
    project: context.project ?? null,
    session: context.session ?? null,
    message: context.message ?? null,
    platform: context.platform ?? null,
    conversation: {
      userTurn: context.conversation?.userTurn ?? null,
      assistantTurn: assistantStore,
    },
    telemetry: {
      assistantStore: $json,
    },
  },
};
